const questionBank=[{category:"Computer Basics",question:"What does CPU stand for?",choices:["Central Processing Unit","Computer Personal Unit","Central Power Utility","Control Program Unit"],answer:"Central Processing Unit",explanation:"CPU means Central Processing Unit. It is often called the brain of the computer because it processes instructions."},{category:"Computer Basics",question:"Which computer part temporarily stores data while the computer is running?",choices:["Hard disk","RAM","Monitor","Keyboard"],answer:"RAM",explanation:"RAM stores data temporarily while the computer is on. When power goes off, data in RAM is lost."},{category:"Computer Basics",question:"Which one is an input device?",choices:["Monitor","Speaker","Keyboard","Printer"],answer:"Keyboard",explanation:"A keyboard is an input device because it sends data and commands into the computer."},{category:"Computer Basics",question:"Which storage device is usually faster than an HDD?",choices:["DVD","SSD","Flashlight","Printer"],answer:"SSD",explanation:"SSD means Solid State Drive. It is usually faster, quieter, and more durable than an HDD."},{category:"Computer Basics",question:"What is the main purpose of an operating system like Windows?",choices:["To wash computer parts","To manage hardware and software","To print only","To increase screen size"],answer:"To manage hardware and software",explanation:"An operating system manages computer hardware, runs programs, and helps the user interact with the computer."},{category:"Computer Basics",question:"Which action sends a deleted file to the Recycle Bin in Windows?",choices:["Rename","Delete","Copy","Refresh"],answer:"Delete",explanation:"Delete removes the file from its current location and normally sends it to the Recycle Bin."},{category:"Computer Basics",question:"Which shortcut is commonly used to copy selected text or files?",choices:["Ctrl + C","Ctrl + V","Ctrl + Z","Ctrl + P"],answer:"Ctrl + C",explanation:"Ctrl + C copies the selected item. Ctrl + V is used to paste it."},{category:"Microsoft Word",question:"Which Microsoft Word feature helps text move around a picture?",choices:["Wrap Text","Sort Text","Zoom Text","Freeze Text"],answer:"Wrap Text",explanation:"Wrap Text controls how words move around a picture or object in a Word document."},{category:"Microsoft Word",question:"Which command is used to make text darker and stronger in Word?",choices:["Italic","Bold","Underline","Align"],answer:"Bold",explanation:"Bold makes text thicker and stronger so it stands out clearly."},{category:"Microsoft Word",question:"Which tab is commonly used to insert pictures, shapes, and text boxes in Word?",choices:["Home","Insert","Review","View"],answer:"Insert",explanation:"The Insert tab is used to add pictures, shapes, text boxes, WordArt, symbols, and more."},{category:"Microsoft Word",question:"Which command is used to save a document quickly?",choices:["Ctrl + S","Ctrl + A","Ctrl + X","Ctrl + F"],answer:"Ctrl + S",explanation:"Ctrl + S saves the current document. It is one of the most important shortcuts for beginners."},{category:"Microsoft Word",question:"What is the purpose of WordArt in Microsoft Word?",choices:["To decorate text","To delete pages","To calculate totals","To scan viruses"],answer:"To decorate text",explanation:"WordArt helps you create decorative text for headings, certificates, posters, and announcements."},{category:"Microsoft Excel",question:"Every Excel formula begins with which symbol?",choices:["+","=","#","@"],answer:"=",explanation:"Every Excel formula begins with an equal sign. Example: =SUM(A1:A5)."},{category:"Microsoft Excel",question:"Which function returns the position of a value in a list?",choices:["SUM","RANK","IF","AVERAGE"],answer:"RANK",explanation:"RANK returns the position of a value in a list, such as 1st, 2nd, or 3rd."},{category:"Microsoft Excel",question:"Which function is used to add numbers in Excel?",choices:["SUM","COUNT","LEFT","LOWER"],answer:"SUM",explanation:"SUM adds numbers together. Example: =SUM(B2:B10)."},{category:"Microsoft Excel",question:"In Excel, what is a cell?",choices:["A box formed by a row and column","A printed paper","A computer cable","A type of virus"],answer:"A box formed by a row and column",explanation:"A cell is the box where a row and a column meet, such as C4."},{category:"Microsoft Excel",question:"Which function helps Excel make a decision?",choices:["IF","SUM","MAX","MIN"],answer:"IF",explanation:"The IF function makes decisions using a condition, value if true, and value if false."},{category:"Microsoft Excel",question:"Which sign is used to lock a cell reference in Excel?",choices:["$","&","!","%"],answer:"$",explanation:"The dollar sign locks a cell reference. Example: $D$4 keeps column D and row 4 fixed."},{category:"Internet & Safety",question:"What does URL mean in simple terms?",choices:["A website address","A keyboard button","A printer cable","A type of monitor"],answer:"A website address",explanation:"A URL is the address used to open a website or web page."},{category:"Internet & Safety",question:"Which one is a strong password habit?",choices:["Use your name only","Use 123456","Use a mix of letters, numbers, and symbols","Share it with everyone"],answer:"Use a mix of letters, numbers, and symbols",explanation:"A strong password should be difficult to guess and should not be shared carelessly."},{category:"Internet & Safety",question:"What should you do before clicking a suspicious link?",choices:["Click quickly","Check if it is safe","Forward it to everyone","Ignore all warnings"],answer:"Check if it is safe",explanation:"Suspicious links can lead to scams, viruses, or fake websites. Always check before clicking."},{category:"Internet & Safety",question:"What does HTTPS show about a website?",choices:["It is using a more secure connection","It has no images","It is always free","It is only for games"],answer:"It is using a more secure connection",explanation:"HTTPS means the website uses a more secure connection than ordinary HTTP."},{category:"Internet & Safety",question:"Which one is an example of personal information you should protect online?",choices:["Your password","A public lesson title","A general computer topic","A keyboard shortcut"],answer:"Your password",explanation:"Passwords are private information. Protect them and avoid sharing them online."},{category:"Internet & Safety",question:"What is email mainly used for?",choices:["Sending and receiving messages online","Making the screen brighter","Cleaning the keyboard","Charging a phone"],answer:"Sending and receiving messages online",explanation:"Email is used to send and receive digital messages through the internet."}];const state={category:"All",questions:[],currentIndex:0,score:0,answered:false,selectedAnswer:""};const elements={categoryTabs:document.getElementById("categoryTabs"),questionCounter:document.getElementById("questionCounter"),scoreCounter:document.getElementById("scoreCounter"),categoryName:document.getElementById("categoryName"),progressBar:document.getElementById("progressBar"),questionTag:document.getElementById("questionTag"),questionText:document.getElementById("questionText"),answerGrid:document.getElementById("answerGrid"),feedbackBox:document.getElementById("feedbackBox"),restartQuiz:document.getElementById("restartQuiz"),nextQuestion:document.getElementById("nextQuestion"),resultSummary:document.getElementById("resultSummary"),resultCircle:document.getElementById("resultCircle"),bestScorePill:document.getElementById("bestScorePill"),shareScore:document.getElementById("shareScore")};function shuffleArray(items){return[...items].sort(()=>Math.random()-0.5);}
function getBestScore(){return Number(localStorage.getItem("athanasQuizBestScore")||0);}
function setBestScore(scorePercent){const best=getBestScore();if(scorePercent>best){localStorage.setItem("athanasQuizBestScore",String(scorePercent));}
updateBestScorePill();}
function updateBestScorePill(){elements.bestScorePill.textContent=`Best: ${getBestScore()}%`;}
function startQuiz(category=state.category){state.category=category;const selectedQuestions=category==="All"?questionBank:questionBank.filter(item=>item.category===category);state.questions=shuffleArray(selectedQuestions).slice(0,Math.min(10,selectedQuestions.length));state.currentIndex=0;state.score=0;state.answered=false;state.selectedAnswer="";elements.resultSummary.textContent="Answer the questions and your final result will appear here.";elements.resultCircle.textContent="0%";elements.nextQuestion.textContent="Next Question";renderQuestion();}
function renderQuestion(){const currentQuestion=state.questions[state.currentIndex];state.answered=false;state.selectedAnswer="";elements.questionCounter.textContent=`${state.currentIndex + 1} / ${state.questions.length}`;elements.scoreCounter.textContent=String(state.score);elements.categoryName.textContent=state.category==="All"?"All Topics":state.category;elements.questionTag.textContent=currentQuestion.category;elements.questionText.textContent=currentQuestion.question;elements.feedbackBox.className="feedback-box";elements.feedbackBox.textContent="";elements.progressBar.style.width=`${(state.currentIndex / state.questions.length) * 100}%`;elements.nextQuestion.disabled=true;elements.answerGrid.innerHTML="";shuffleArray(currentQuestion.choices).forEach(choice=>{const button=document.createElement("button");button.type="button";button.className="answer-btn";button.textContent=choice;button.addEventListener("click",()=>selectAnswer(button,choice));elements.answerGrid.appendChild(button);});}
function selectAnswer(button,choice){if(state.answered)return;const currentQuestion=state.questions[state.currentIndex];const isCorrect=choice===currentQuestion.answer;state.answered=true;state.selectedAnswer=choice;if(isCorrect){state.score+=1;elements.feedbackBox.className="feedback-box correct";elements.feedbackBox.innerHTML=`<strong>Correct — from confusion to clarity!</strong> ${currentQuestion.explanation}`;}else{elements.feedbackBox.className="feedback-box wrong";elements.feedbackBox.innerHTML=`<strong>Good try — mistakes teach.</strong> The correct answer is <strong>${currentQuestion.answer}</strong>. ${currentQuestion.explanation}`;}
[...elements.answerGrid.children].forEach(answerButton=>{answerButton.disabled=true;if(answerButton.textContent===currentQuestion.answer){answerButton.classList.add("correct-answer");}});if(!isCorrect){button.classList.add("wrong-answer");}
elements.scoreCounter.textContent=String(state.score);elements.nextQuestion.disabled=false;if(state.currentIndex===state.questions.length-1){elements.nextQuestion.textContent="See Result";}}
function nextQuestion(){if(!state.answered)return;if(state.currentIndex<state.questions.length-1){state.currentIndex+=1;renderQuestion();}else{finishQuiz();}}
function finishQuiz(){const percentage=Math.round((state.score/state.questions.length)*100);setBestScore(percentage);elements.progressBar.style.width="100%";elements.resultCircle.textContent=`${percentage}%`;let message="Good start. Keep practicing — ICT confidence grows by doing, not by fearing mistakes.";if(percentage>=80){message="Excellent work! You are building strong ICT confidence — Athanas Inspires style.";}else if(percentage>=50){message="Nice effort! Review the explanations, try again, and move one step closer to clarity.";}
elements.resultSummary.textContent=`${message} You scored ${state.score} out of ${state.questions.length} in ${state.category === "All" ? "All Topics" : state.category}.`;elements.nextQuestion.disabled=true;elements.nextQuestion.textContent="Quiz Complete";}
function shareScore(){const percentageText=elements.resultCircle.textContent||"0%";const summary=elements.resultSummary.textContent||"I practiced with the Athanas Inspires General ICT Quiz Game.";const pageUrl=window.location.href;const message=`I practiced with the Athanas Inspires General ICT Quiz Game and scored ${percentageText}! ${summary} Try it here: ${pageUrl}`;window.open(`https://wa.me/?text=${encodeURIComponent(message)}`,"_blank","noopener,noreferrer");}
elements.categoryTabs.addEventListener("click",event=>{const tab=event.target.closest(".category-tab");if(!tab)return;document.querySelectorAll(".category-tab").forEach(item=>item.classList.remove("active"));tab.classList.add("active");startQuiz(tab.dataset.category);});elements.restartQuiz.addEventListener("click",()=>startQuiz(state.category));elements.nextQuestion.addEventListener("click",nextQuestion);elements.shareScore.addEventListener("click",shareScore);updateBestScorePill();startQuiz("All");